arguments.new_str:
var builder = WebApplication.CreateBuilder(args);

// FIX (Breaking Change 1 — ValidateScopes in development):
// .NET 9 enables ValidateScopes by default in Development. A Singleton that
// resolves a Scoped service from the root container will throw
// InvalidOperationException at startup. Change ICacheService to Scoped so it
// doesn't capture a Scoped IUserService in a longer-lived scope.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// FIX (Breaking Change 2 — HttpClientFactory uses SocketsHttpHandler):
// .NET 9 changed the default primary handler from HttpClientHandler to
// SocketsHttpHandler. The previous cast to HttpClientHandler throws
// InvalidCastException. Use ConfigurePrimaryHttpMessageHandler instead.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false });

// FIX (Breaking Change 3 — HttpClientFactory header redaction):
// .NET 9 redacts all header values in Trace-level HttpClientFactory logs by
// default. Allowlist the specific non-sensitive headers you need to inspect.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(name =>
        name != "X-Request-Id"
        && name != "X-Correlation-Id"
        && name != "Cache-Control"
        && name != "Accept"
        && name != "Content-Type"));

// FIX (Breaking Change 4 — Forwarded headers ignore unknown proxies):
// .NET 9 ForwardedHeadersMiddleware silently drops X-Forwarded-* headers from
// proxies not listed in KnownProxies or KnownNetworks. Add your reverse-proxy
// addresses here so the headers are processed.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with actual reverse-proxy IP(s) or CIDR ranges
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

// NOTE (Breaking Change 5 — dotnet watch + Hot Reload):
// dotnet watch in the .NET 9 SDK does not support Hot Reload when targeting
// older frameworks. Since we now target net9.0, dotnet watch works normally.
// If you multi-target net8.0, use the .NET 8 SDK for watch sessions on that TFM.

